// ─────────────────────────────────────────────────────────────
// Parse the incoming request body.
// The app sends Content-Type: text/plain (to avoid CORS preflight),
// so n8n delivers the raw JSON string in .body — we JSON.parse it.
// ─────────────────────────────────────────────────────────────
const raw = $('Receive trip request').item.json.body;

// Handle: already parsed object, plain text string, or missing
let body;
if (typeof raw === 'string') {
  try { body = JSON.parse(raw); } catch(e) { body = {}; }
} else if (raw && typeof raw === 'object') {
  body = raw;
} else {
  body = {};
}

// ── Respond immediately to pings (used by Test Connection button) ──
if (body._ping) {
  return [{ json: { pong: true, status: 'ok', message: 'Itinera n8n workflow is live.' } }];
}

// ─────────────────────────────────────────────────────────────
// Build the OpenAI prompt
// ─────────────────────────────────────────────────────────────
const SYSTEM_PROMPT = `You are an expert travel planner. Given trip inputs, return ONLY a single valid JSON object — no markdown fences, no prose, no comments, just raw JSON.

Return EXACTLY this structure:
{
  "id": "custom",
  "city": "<destination city name>",
  "country": "<country name>",
  "persona": "<same as input persona>",
  "days": <integer>,
  "tagline": "<one evocative sentence about this trip>",
  "plan": [
    {
      "day": <integer starting at 1>,
      "title": "<poetic day title e.g. Temples & Tea>",
      "items": [
        {
          "time": "<e.g. 9:00 AM>",
          "title": "<activity name using real place names>",
          "cat": "<one of: dining | cruise | adventure | relaxing | sightseeing>",
          "cost": <integer USD per person for this activity only — 0 if free>,
          "tip": "<two insider sentences: practical advice, local knowledge. Non-obvious, specific>",
          "kids": <true if suitable for children, false otherwise>
        }
      ]
    }
  ],
  "omitted": [
    {
      "time": "<e.g. Evening>",
      "title": "<great activity that didn't fit the schedule>",
      "cat": "<valid category>",
      "cost": <integer USD>,
      "tip": "<brief practical tip>"
    }
  ]
}

Rules:
- 3 to 5 items per day, vary categories
- Exactly 3 items in omitted
- Use real place names and authentic local recommendations
- Costs = activity entry/experience per person only (no flights, no hotels)
- Tips must be specific and non-obvious
- Persona: Budget = cheap/free, Mid-range = mid-tier, Luxurious = premium, Adventure = active/outdoors`;

const days = body.days || 3;
const persona = body.persona || 'Mid-range';
const destination = body.destination || 'Paris';
const adults = (body.adults_m || 0) + (body.adults_f || 0) || 2;
const kids = body.kids || 0;
const mustHave = body.mustHave || 'none specified';
const start = body.startDate || 'flexible';
const end = body.endDate || 'flexible';

const userMessage = `Plan a ${days}-day ${persona} trip to ${destination}.\nGroup: ${adults} adult(s), ${kids} kid(s).\nDates: ${start} to ${end}.\nMust-haves: ${mustHave}.`;

return [{
  json: {
    _originalBody: body,
    model: 'gpt-4o-mini',
    response_format: { type: 'json_object' },
    max_tokens: 4096,
    messages: [
      { role: 'system', content: SYSTEM_PROMPT },
      { role: 'user',   content: userMessage }
    ]
  }
}];

// ── Short-circuit: return pong immediately for _ping requests ──
const body = $input.item.json;
if (body._originalBody && body._originalBody._ping) {
  return [{ json: { pong: true, status: 'ok' } }];
}
// Otherwise pass through for the HTTP Request node
return [{ json: body }];

// ─────────────────────────────────────────────────────────────
// Parse the OpenAI response and return a clean trip object.
// ─────────────────────────────────────────────────────────────
const response = $input.item.json;

// Handle ping short-circuit
if (response.pong) return [{ json: response }];

if (!response.choices || response.choices.length === 0) {
  throw new Error('OpenAI returned no choices. Response: ' + JSON.stringify(response).slice(0, 300));
}

const content = response.choices[0].message.content;
let trip;
try {
  trip = JSON.parse(content);
} catch (e) {
  // Strip markdown fences if present
  const cleaned = content.replace(/^```json\s*/i, '').replace(/```\s*$/i, '').trim();
  try {
    trip = JSON.parse(cleaned);
  } catch (e2) {
    throw new Error('Failed to parse AI JSON. Content: ' + content.slice(0, 300));
  }
}

// Validate and sanitise
if (!trip.plan || !Array.isArray(trip.plan) || trip.plan.length === 0) {
  throw new Error("AI response missing 'plan' array. Got: " + JSON.stringify(trip).slice(0, 300));
}
if (!Array.isArray(trip.omitted)) trip.omitted = [];

const validCats = new Set(['dining','cruise','adventure','relaxing','sightseeing']);
for (const day of trip.plan) {
  for (const item of (day.items || [])) {
    if (!validCats.has(item.cat)) item.cat = 'sightseeing';
    if (typeof item.cost !== 'number') item.cost = 0;
    if (typeof item.kids !== 'boolean') item.kids = false;
    if (!item.tip) item.tip = 'A wonderful experience worth your time.';
  }
}

trip.id = trip.id || 'custom';

return [{ json: trip }];
